/// @brief Speech activity event type
///
/// Mirrors Swift's SpeechActivityEvent.
enum rac_speech_activity {
  RAC_SPEECH_STARTED(0),
  RAC_SPEECH_ENDED(1),
  RAC_SPEECH_ONGOING(2);

  final int value;
  const rac_speech_activity(this.value);

  static rac_speech_activity fromValue(int value) => switch (value) {
        0 => RAC_SPEECH_STARTED,
        1 => RAC_SPEECH_ENDED,
        2 => RAC_SPEECH_ONGOING,
        _ =>
          throw ArgumentError("Unknown value for rac_speech_activity: $value"),
      };
}

